    xml_tree = etree.fromstring(xml_string)
    
    # Extract the message body
    body_element = xml_tree.find(".//{http://schemas.xmlsoap.org/soap/envelope/}Body")
    if body_element is None:
        raise ValueError("SOAP body not found in request")
    
    message_body = etree.tostring(body_element, pretty_print=True).decode()
    
    return message_body